def range_summary(nums):
    if not nums:
        return ''

    distinct_nums = sorted(set(nums))
    result = []
    start = end = None

    for num in distinct_nums:
        if start is None or num != end + 1:
            if start is not None:
                if start == end:
                    result.append(str(start))
                else:
                    result.append(f'{start}-{end}')
            start = end = num
        else:
            end += 1

    if start is not None:
        if start == end:
            result.append(str(start))
        else:
            result.append(f'{start}-{end}')

    return ','.join(result)
